1434: func rulesAlertsToAPIAlerts(rulesAlerts []*rules.Alert) []*Alert {
1435: 	apiAlerts := make([]*Alert, len(rulesAlerts))
1436: 	for i, ruleAlert := range rulesAlerts {
1437: 		apiAlerts[i] = &Alert{
1438: 			Labels:      ruleAlert.Labels,
1439: 			Annotations: ruleAlert.Annotations,
1440: 			State:       ruleAlert.State.String(),
1441: 			ActiveAt:    &ruleAlert.ActiveAt,
1442: 			Value:       strconv.FormatFloat(ruleAlert.Value, 'e', -1, 64),
1443: 		}
