1452: func (api *API) metricMetadata(r *http.Request) apiFuncResult {
1453: 	metrics := map[string]map[metadata.Metadata]struct{}{}
1454: 
1455: 	limit := -1
1456: 	if s := r.FormValue("limit"); s != "" {
1457: 		var err error
1458: 		if limit, err = strconv.Atoi(s); err != nil {
1459: 			return apiFuncResult{nil, &apiError{errorBadData, errors.New("limit must be a number")}, nil, nil}
1460: 		}
1461: 	}
1462: 	limitPerMetric := -1
1463: 	if s := r.FormValue("limit_per_metric"); s != "" {
1464: 		var err error
1465: 		if limitPerMetric, err = strconv.Atoi(s); err != nil {
1466: 			return apiFuncResult{nil, &apiError{errorBadData, errors.New("limit_per_metric must be a number")}, nil, nil}
1467: 		}
1468: 	}
1469: 
1470: 	metric := r.FormValue("metric")
1471: 	for _, tt := range api.targetRetriever(r.Context()).TargetsActive() {
1472: 		for _, t := range tt {
1473: 			if metric == "" {
1474: 				for _, mm := range t.ListMetadata() {
1475: 					m := metadata.Metadata{Type: mm.Type, Help: mm.Help, Unit: mm.Unit}
1476: 					ms, ok := metrics[mm.MetricFamily]
1477: 
1478: 					if limitPerMetric > 0 && len(ms) >= limitPerMetric {
1479: 						continue
1480: 					}
1481: 
1482: 					if !ok {
1483: 						ms = map[metadata.Metadata]struct{}{}
1484: 						metrics[mm.MetricFamily] = ms
1485: 					}
1486: 					ms[m] = struct{}{}
1487: 				}
1488: 				continue
1489: 			}
1490: 
1491: 			if md, ok := t.GetMetadata(metric); ok {
1492: 				m := metadata.Metadata{Type: md.Type, Help: md.Help, Unit: md.Unit}
1493: 				ms, ok := metrics[md.MetricFamily]
1494: 
1495: 				if limitPerMetric > 0 && len(ms) >= limitPerMetric {
1496: 					continue
1497: 				}
1498: 
1499: 				if !ok {
1500: 					ms = map[metadata.Metadata]struct{}{}
1501: 					metrics[md.MetricFamily] = ms
1502: 				}
1503: 				ms[m] = struct{}{}
1504: 			}
1505: 		}
1506: 	}
1507: 
1508: 	// Put the elements from the pseudo-set into a slice for marshaling.
1509: 	res := map[string][]metadata.Metadata{}
