1511: 		if limit >= 0 && len(res) >= limit {
1512: 			break
1513: 		}
1514: 
1515: 		s := []metadata.Metadata{}
1516: 		for metadata := range set {
1517: 			s = append(s, metadata)
1518: 		}
1519: 		res[name] = s
1520: 	}
